"""Apply local Colab fixes when GitHub main is behind. Run: python scripts/colab_apply_fixes.py"""
from __future__ import annotations

import base64
from pathlib import Path

ROOT = Path(__file__).resolve().parent

# Embedded copies of fixed scripts (base64, UTF-8)
CALIBRATE_B64 = (
    ""
)

MODEL_UTILS_B64 = (
    ""
)

FORMAT_CHAT_SNIPPET = '''

def format_chat(
    tokenizer,
    messages: list[dict],
    *,
    add_generation_prompt: bool = False,
) -> str:
    """Apply chat template; disable Qwen3 thinking mode when supported."""
    kwargs = {
        "tokenize": False,
        "add_generation_prompt": add_generation_prompt,
    }
    try:
        return tokenizer.apply_chat_template(messages, enable_thinking=False, **kwargs)
    except TypeError:
        return tokenizer.apply_chat_template(messages, **kwargs)
'''


def write_b64(path: Path, b64: str) -> None:
    path.write_bytes(base64.b64decode(b64))
    print(f"Wrote {path}")


def ensure_format_chat(common_path: Path) -> None:
    text = common_path.read_text(encoding="utf-8")
    if "def format_chat" in text:
        print(f"{common_path} already has format_chat")
        return
    marker = "def parse_label"
    if marker not in text:
        raise SystemExit(f"Could not patch {common_path}: missing {marker}")
    text = text.replace(marker, FORMAT_CHAT_SNIPPET + "\n\n" + marker)
    common_path.write_text(text, encoding="utf-8")
    print(f"Patched {common_path} with format_chat")


def main() -> None:
    write_b64(ROOT / "calibrate.py", CALIBRATE_B64)
    write_b64(ROOT / "model_utils.py", MODEL_UTILS_B64)
    ensure_format_chat(ROOT / "common.py")
    print("Done. Re-run calibrate with --max-examples 100")


if __name__ == "__main__":
    main()
